<?php
namespace App\Providers; use DB;
class PaperBroker implements BrokerInterface{public function getAccount():array{return DB::pdo()->query('SELECT * FROM paper_accounts WHERE id=1')->fetch()?:[];} public function getPositions():array{return DB::pdo()->query("SELECT * FROM positions WHERE broker='paper'")->fetchAll();} public function getOrders():array{return DB::pdo()->query("SELECT * FROM orders WHERE provider='paper' ORDER BY id DESC")->fetchAll();} public function getBalance():float{return (float)($this->getAccount()['buying_power']??0);} public function placeOrder(array $o):array{$price=(float)($o['limit_price']??$o['price']??0);$qty=(float)$o['qty'];$st=DB::pdo()->prepare('INSERT INTO orders(symbol,side,type,qty,limit_price,stop_price,status,provider,raw) VALUES(?,?,?,?,?,?,?,?,?)');$st->execute([$o['symbol'],$o['side'],$o['type']??'market',$qty,$o['limit_price']??null,$o['stop_price']??null,'open','paper',json_encode($o)]);return ['id'=>DB::pdo()->lastInsertId(),'status'=>'open'];} public function cancelOrder(int|string $id):bool{DB::pdo()->prepare("UPDATE orders SET status='cancelled' WHERE id=? AND status='open'")->execute([$id]);return true;} public function modifyOrder(int|string $id,array $c):array{$allowed=['qty','limit_price','stop_price'];$sets=[];$vals=[];foreach($allowed as $a)if(isset($c[$a])){$sets[]="$a=?";$vals[]=$c[$a];}$vals[]=$id;if($sets)DB::pdo()->prepare('UPDATE orders SET '.implode(',',$sets).' WHERE id=?')->execute($vals);return ['id'=>$id,'status'=>'modified'];}}
